mapper.select:
SELECT school_id AS schoolId, school_name AS campusName, school_code AS campusCode, status, create_time AS createTime FROM sys_school
AND status = #{req.status}
ORDER BY create_time DESC

SELECT d.stage_id AS stageId, d.stage_name AS stageName, d.school_id AS schoolId, s.school_name AS campusName, d.stage_order AS stageOrder, d.status, d.create_time AS createTime FROM sys_design_stage d LEFT JOIN sys_school s ON s.school_id = d.school_id
AND d.school_id = #{req.schoolId}
AND d.status = #{req.status}
ORDER BY d.stage_order ASC, d.create_time ASC

SELECT g.grade_id AS gradeId, g.grade_name AS gradeName, g.school_id AS schoolId, s.school_name AS campusName, g.grade_year AS gradeYear, g.status, g.create_time AS createTime FROM sys_grade g LEFT JOIN sys_school s ON s.school_id = g.school_id
AND g.school_id = #{req.schoolId}
AND g.status = #{req.status}
ORDER BY g.grade_year DESC, g.create_time DESC

SELECT t.slot_id AS slotId, t.slot_name AS slotName, t.school_id AS schoolId,
       s.school_name AS campusName, t.slot_type AS slotType,
       t.start_date AS startDate, t.end_date AS endDate, t.slot_order AS slotOrder,
       t.status, t.create_time AS createTime
FROM sys_time_slot t
LEFT JOIN sys_school s ON s.school_id = t.school_id


        AND t.school_id = #{req.schoolId}


        AND t.slot_type = #{req.type}


        AND t.status = #{req.status}


ORDER BY t.slot_order ASC, t.create_time ASC
